class Solution {
public:
    int makeTheIntegerZero(int num1, int num2) {
        long long n1 = num1, n2 = num2;
        for (int i = 0; i <= 30; ++i) {
            int cnt = 0;
            long long x = n1 - i * n2;
            if (x < 0) break;
            while (x) {
                cnt += x & 1;
                x >>= 1;
            }
            if (cnt <= i && i <= x + i) return i;
        }
        return -1;
    }
};
